function toUtc(raw){ if(!raw) return null;
  const m = raw.match(/^(\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2})\s*([+-]\d{4})?$/); if(!m) return null;
  const base = m[1].replace(' ', 'T'); if(!m[2]) return base;
  const sign = m[2][0]==='+'?1:-1; const oh=parseInt(m[2].substring(1,3)); const om=parseInt(m[2].substring(3,5));
  const dt = new Date(base+'Z'); dt.setMinutes(dt.getMinutes() - sign*(oh*60+om));
  return dt.toISOString().replace('T',' ').substring(0,19);
}
const body = items[0].json.body; const inner = body.data || {};
const metrics = inner.metrics || (Array.isArray(body.data) ? body.data : []);
const workouts = inner.workouts || []; const rows = [];
for (const metric of metrics) {
  const name = metric.name; const unit = metric.units || '';
  if (name === 'sleep_analysis') {
    for (const p of (metric.data||[])) { const ts = toUtc(p.sleepStart||p.date); if(!ts) continue;
      for (const k of ['totalSleep','deep','rem','core','awake']) if (p[k]!==undefined)
        rows.push({ metric: 'sleep_'+(k==='totalSleep'?'total':k), timestamp: ts, value: Number(p[k]), unit: 'hr' });
    } continue;
  }
  for (const p of (metric.data||[])) { const ts = toUtc(p.date||p.startDate);
    const val = p.qty!==undefined?p.qty:(p.Avg!==undefined?p.Avg:p.value);
    if(!ts||val==null) continue; rows.push({ metric: name, timestamp: ts, value: Number(val), unit });
  }
}
for (const w of workouts) { const ts = toUtc(w.start||w.startDate); const tsEnd = toUtc(w.end); if(!ts) continue;
  const name = w.name || 'Workout';
  if (tsEnd) rows.push({ metric:'WorkoutDuration', timestamp:ts, value:Math.round(Math.abs((new Date(tsEnd+'Z')-new Date(ts+'Z'))/1000)), unit:name });
  if (w.activeEnergy?.qty!==undefined) rows.push({ metric:'WorkoutActiveCalories', timestamp:ts, value:Number(w.activeEnergy.qty), unit:name });
  if (w.distance?.qty!==undefined) rows.push({ metric:'WorkoutDistance', timestamp:ts, value:Number(w.distance.qty), unit:w.distance.units||'km' });
  if (w.speed?.qty!==undefined) rows.push({ metric:'WorkoutSpeed', timestamp:ts, value:Number(w.speed.qty), unit:w.speed.units||'km/hr' });
}
const CHUNK=500; const queries=[];
for (let i=0;i<rows.length;i+=CHUNK) { const chunk=rows.slice(i,i+CHUNK);
  const values = chunk.map(r => "('"+String(r.timestamp).replace(/'/g,"''")+"', '"+String(r.metric).replace(/'/g,"''")+"', "+r.value+", '"+String(r.unit||'').replace(/'/g,"''")+"', 'health-auto-export')").join(',');
  queries.push("INSERT INTO apple_health (timestamp, metric, value, unit, source) VALUES "+values+" ON CONFLICT DO NOTHING");
}
if (queries.length===0) return [{ json:{ query:'SELECT 1', total:0 } }];
return queries.map((query,i) => ({ json:{ query, batch:i+1, total_rows:rows.length } }));
